package com.clashcoach.player;
import javax.validation.Valid; import java.util.UUID; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/players/me") public class PlayerController { private final PlayerService service; public PlayerController(PlayerService service){this.service=service;} @GetMapping PlayerDtos.PlayerResponse profile(@AuthenticationPrincipal UUID userId){return service.profile(userId);}@PutMapping @ResponseStatus(HttpStatus.CREATED) PlayerDtos.PlayerResponse link(@AuthenticationPrincipal UUID userId,@Valid @RequestBody PlayerDtos.LinkRequest request){return service.link(userId,request.getPlayerTag());}@PostMapping("/refresh") PlayerDtos.PlayerResponse refresh(@AuthenticationPrincipal UUID userId){return service.refresh(userId);}@GetMapping("/recommendation") PlayerDtos.RecommendationResponse recommendation(@AuthenticationPrincipal UUID userId){return service.recommendation(userId);} }
